#include <stdio.h>
#include <stdlib.h>

#define MAX_M 700
#define MAX_N 700

int min_colors[MAX_M][MAX_N];
int graph[MAX_M * MAX_N][MAX_M * MAX_N];

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N;
        scanf("%d %d", &M, &N);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                char c;
                scanf(" %c", &c);
                if (c == '1') {
                    // Add edges to the graph
                    for (int k = 0; k < N; k++) {
                        if (k != j) {
                            graph[i * N + j][i * N + k] = 1;
                        }
                    }
                    for (int k = 0; k < M; k++) {
                        if (k != i) {
                            graph[i * N + j][k * N + j] = 1;
                        }
                    }
                }
            }
        }
        // Assign colors using a greedy algorithm
        int max_color = 0;
        for (int i = 0; i < M * N; i++) {
            int color = 1;
            while (1) {
                int used = 0;
                for (int j = 0; j < M * N; j++) {
                    if (graph[i][j] && min_colors[j / N][j % N] == color) {
                        used = 1;
                        break;
                    }
                }
                if (!used) {
                    min_colors[i / N][i % N] = color;
                    max_color = (max_color > color) ? max_color : color;
                    break;
                }
                color++;
            }
        }
        printf("%d\n", max_color);
        for (int i = 0; i < M; i++) {
            for (int j = 0; j < N; j++) {
                printf("%d ", min_colors[i][j]);
            }
            printf("\n");
        }
        printf("\n");
    }
    return 0;
}

